fun solve(grid: Array<Array<Long>>, x: Long, y: Long, k: Long): Array<Array<Long>> {
    // Create a copy of the grid to avoid modifying the original
    val matrix = grid.map { it.toTypedArray() }.toTypedArray()

    // Extract the submatrix
    val submatrix = Array(k) { row ->
        Array(k) { col -> matrix[x.toInt() + row][y.toInt() + col] }
    }

    // Reverse the submatrix
    val reversedSubmatrix = Array(k) { row ->
        Array(k) { col -> submatrix[k - 1 - row][col] }
    }

    // Replace the original submatrix with the reversed one
    for (i in 0 until k) {
        for (j in 0 until k) {
            matrix[x.toInt() + i][y.toInt() + j] = reversedSubmatrix[i][j]
        }
    }

    return matrix
}
